# agentic_I2 skeptic-crosscheck · S06-T2-B-E3
def dedup_report(rows, key='id'):
    seen = {}
    unique = []
    conflicts = []
    for name in rows:
        k = name[key]
        if k not in seen:
            seen[k] = name
            unique.append(name)
        elif seen[k] != name:
            conflicts.append({'key': k, 'kept': seen[k], 'other': name})
    return {'unique': unique, 'conflicts': conflicts}
rows = [
    {'id': 'C001', 'v': 1},
    {'id': 'C002', 'v': 2},
    {'id': 'C001', 'v': 9},
]
print(dedup_report(rows))

