# agentic_I2 skeptic-crosscheck · S06-T3-B-E1
def get_nested(d, *keys, default=None):
    cur = d
    for k in keys:
        if not isinstance(cur, dict) or k not in cur:
            return default
        cur = cur[k]
    return cur
c = {'profile': {'phone': '999'}}
print(get_nested(c, 'profile', 'phone'))
print(get_nested(c, 'profile', 'email', default='N/A'))

